     <column id=\"rosterStatus\" name=\"IFNULL( d.roster_status, \'\') \" title=\"Roster Status\" primary=\"false\" />\n                        <column id=\"rosteredDate\" name=\"IF(d.roster_date IS NOT NULL, DATE_FORMAT( d.roster_date, \'%m-%d-%Y\'), \'\')\" title=\"Rostered Date (mm-dd-yyyy)\" primary=\"false\" />\n			<column id=\"lastVisit\" name=\"IF(app1.appointment_date IS NOT NULL, DATE_FORMAT( app1.appointment_date, \'%m-%d-%Y\'),\'\')\" title=\"Date of Last Visit (mm-dd-yyyy)\" primary=\"false\" />\n\n		</exportColumns>\n		<query>\n			<!-- Drilldown SQL Query here -->\n			\n			SELECT\n				d.*,\n				d.patient_status AS pt_status\n				FROM demographic d\n			\n				\n				-- Notations for last visit in appointments\n				LEFT JOIN (\n        				SELECT a.demographic_no, max(a.appointment_date) as appointment_date\n        				FROM appointment a, demographic d\n        				WHERE a.demographic_no = d.demographic_no\n        				AND d.provider_no = \'${provider}\'\n        				AND NOW() > DATE(a.appointment_date)\n        				AND a.status != \'D\' AND a.status != \'C\' AND a.status != \'N\'\n        				AND a.demographic_no > 0\n        				GROUP BY a.demographic_no\n				) app1 \n				ON (d.demographic_no = app1.demographic_no)\n\n				WHERE d.patient_status = \'AC\'\n				AND d.provider_no = \'${provider}\'\n                                AND ( DATEDIFF(CURDATE(), app1.appointment_date) > 730  OR app1.appointment_date IS NULL )\n\n\n		</query>\n	</drillDownQuery>\n	<shared>false</shared>\n	<sharedMetricSetName>OntarioMD Patient Status</sharedMetricSetName>\n	<sharedMetricDataId>Status</sharedMetricDataId>\n	<sharedMappings>\n		<sharedMapping fromLabel=\"% Active, Seen within 12 months\" toLabel=\"Active, seen this year\"/>\n		<sharedMapping fromLabel=\"% Active, Seen 12-24 months ago\" toLabel=\"Active, seen within 1-2 yrs\"/>\n		<sharedMapping fromLabel=\"% Active, not seen in 24 months\" toLabel=\"Active, not seen in 2+ yrs\"/>\n		<sharedMapping fromLabel=\"% Inactive\" toLabel=\"Inactive\"/>\n		<sharedMapping fromLabel=\"% Deceased\" toLabel=\"Deceased\"/>\n		<sharedMapping fromLabel=\"% Other Patient Status\" toLabel=\"Other\"/>\n	</sharedMappings>	\n</indicatorTemplateXML>\n', b'1', b'0', 0, 'Active, not seen in 2+ yrs', 'OntarioMD Patient Status'),
(1144, 6, 'Active Seen This Year', 'OntarioMD Prac. Management', 'OMD-Patient Status', 'OSCAR EMR', '2018-02-14', '% of patients (Rostered and non-Rostered) in the practice based on their status, including last visit.', '', '<?xml version=\"1.0\" encoding=\"UTF-8\"?>\n<indicatorTemplateXML>\n	<author>Trinity Healthcare Technologies</author>\n	<uid></uid>\n	<heading>\n		<category>Practice Management</category>\n		<subCategory>OSCAR Patient Status</subCategory>\n		<name>Active Seen This Year</name>\n		<metricSetName>OntarioMD Patient Status</metricSetName>\n                <metricLabel>Active, seen this year</metricLabel>\n		<definition>% of patients (Rostered and non-Rostered) in the practice based on their status, including last visit.</definition>\n		<framework>OSCAR EMR</framework>\n		<frameworkVersion>02-14-2018</frameworkVersion>\n		<notes></notes>\n	</heading>\n	<indicatorQuery>\n		<version>02-14-2018</version>\n		<params>\n			<!-- \n				Use this parameter in the query as ${provider}\n				This parameter should be used for fetching patient\'s assigned to a MRP.\n				ie: WHERE demographic.provider_no = ${provider}\n			-->\n			<parameter id=\"provider\" name=\"provider_no\" value=\"loggedInProvider\" />\n			<parameter id=\"pstatus\" name=\"Patient Status\" value=\"\'AC\'\" />\n		</params>\n		<query>\n			<!-- Indicator SQL Query here -->\n			SELECT\n\n				-- PERCENT OF TOTAL PATIENTS NOTED AS ACTIVE SEEN WITHIN 12 MONTHS (latest visit &lt;= 12 months)\n				IF( COUNT(fin.patient) > 0, \n					SUM( IF( fin.pt_status = \'AC\' and DATEDIFF(CURDATE(),fin.last_visit) &lt;= 365  , 1, 0) )\n				, 0 ) AS \"% Active, Seen within 12 months\",\n			\n				-- PERCENT OF TOTAL PATIENTS NOTED AS ACTIVE SEEN 12-24 MONTHS AGO (latest visit &gt; 12 months and &lt; 24 months)\n				IF( COUNT(fin.patient) > 0, \n					 SUM( IF( fin.pt_status = \'AC\' and DATEDIFF(CURDATE(),fin.last_visit) > 365 and DATEDIFF(CURDATE(),fin.last_visit) &lt;= 730  , 1, 0) )\n				, 0 ) AS \"% Active, Seen 12-24 months ago\",\n				\n				-- PERCENT OF TOTAL PATIENTS NOTED AS ACTIVE NOT SEEN WITHIN 24 MONTHS (latest visit &gt; 24 months)\n				IF( COUNT(fin.patient) > 0, \n					SUM( IF( fin.pt_status = \'AC\' and (DATEDIFF(CURDATE(),fin.last_visit) > 730 OR fin.last_visit IS NULL)  , 1, 0) )\n				, 0 ) AS \"% Active, not seen in 24 months\",\n				\n				-- PERCENT OF TOTAL PATIENTS NOTED AS INACTIVE\n				IF( COUNT(fin.patient) > 0, \n					 SUM( IF( fin.pt_status = \'IN\' , 1, 0) )\n				, 0 ) AS \"% Inactive\",\n				\n				-- PERCENT OF TOTAL PATIENTS NOTED AS DECEASED\n				IF( COUNT(fin.patient) > 0, \n					  SUM( IF( fin.pt_status = \'DE\' , 1, 0) )\n				, 0 ) AS \"% Deceased\",\n				\n				-- PERCENT OF TOTAL PATIENTS NOTED AS OTHER (not active, not inactive, not deceased, not deleted?)\n				IF( COUNT(fin.patient) > 0, \n					  SUM( IF( fin.pt_status NOT IN (\'AC\',\'DE\',\'IN\') , 1, 0) )\n				, 0 ) AS \"% Other Patient Status\"\n				\n\n			FROM (\n				SELECT\n					d.demographic_no AS patient,\n					d.patient_status AS pt_status,\n					app1.appointment_date as last_visit\n				FROM demographic d\n			\n				\n				-- Notations for last visit in appointments\n				LEFT JOIN ( \n					SELECT a.demographic_no, max(a.appointment_date) as appointment_date\n        				FROM appointment a, demographic d\n        				WHERE a.demographic_no = d.demographic_no\n        				AND d.provider_no = \'${provider}\'\n        				AND NOW() >= DATE(a.appointment_date)\n        				AND a.status != \'D\' AND a.status != \'C\' AND a.status != \'N\'\n        				AND a.demographic_no > 0\n        				GROUP BY a.demographic_no\n				) app1 \n				ON (d.demographic_no = app1.demographic_no)\n\n				WHERE d.provider_no = \'${provider}\'\n			) fin\n		</query>\n	</indicatorQuery>\n	<drillDownQuery>\n		<version>02-14-2018</version>\n		<params>\n			<parameter id=\"provider\" name=\"provider_no\" value=\"loggedInProvider\" />	\n		</params>\n		<displayColumns>\n			<column id=\"demographic\" name=\"d.demographic_no\" title=\"Patient Id\" primary=\"true\" />\n			<column id=\"name\" name=\"CONCAT( d.last_name, \', \', d.first_name )\" title=\"Patient Name\" primary=\"false\" />\n			<column id=\"dob\" name=\"DATE_FORMAT( CONCAT(d.year_of_birth,\'-\',d.month_of_birth,\'-\',d.date_of_birth), \'%m-%d-%Y\' )\" title=\"Patient DOB (mm-dd-yyyy)\" primary=\"false\" />\n			<column id=\"age\" name=\"FLOOR( ABS( DATEDIFF( DATE( CONCAT(d.year_of_birth,\'-\',d.month_of_birth,\'-\',d.date_of_birth) ), NOW() ) ) / 365.25 )\" title=\"Patient Age\" primary=\"false\" />	\n                        <column id=\"phonenumber\" name=\"IFNULL( d.phone, \'\')\" title=\"Patient Phone Number\" primary=\"false\" />\n			<column id=\"rosterStatus\" name=\"IFNULL( d.roster_status, \'\') \" title=\"Roster Status\" primary=\"false\" />\n			<column id=\"rosteredDate\" name=\"IF(d.roster_date IS NOT NULL, DATE_FORMAT( d.roster_date, \'%m-%d-%Y\'), \'\')\" title=\"Rostered Date (mm-dd-yyyy)\" primary=\"false\" />\n			<column id=\"lastVisit\" name=\"IF(app1.appointment_date IS NOT NULL, DATE_FORMAT( app1.appointment_date, \'%m-%d-%Y\'),\'\')\" title=\"Date of Last Visit (mm-dd-yyyy)\" primary=\"false\" />\n		</displayColumns>\n		<exportColumns>\n			<column id=\"demographic\" name=\"d.demographic_no\" title=\"Patient Id\" primary=\"true\" />\n			<column id=\"name\" name=\"CONCAT( d.last_name, \', \', d.first_name )\" title=\"Patient Name\" primary=\"false\" />\n			<column id=\"dob\" name=\"DATE_FORMAT( CONCAT(d.year_of_birth,\'-\',d.month_of_birth,\'-\',d.date_of_birth), \'%m-%d-%Y\' )\" title=\"Patient DOB (mm-dd-yyyy)\" primary=\"false\" />\n                        <column id=\"age\" name=\"FLOOR( ABS( DATEDIFF( DATE( CONCAT(d.year_of_birth,\'-\',d.month_of_birth,\'-\',d.date_of_birth) ), NOW() ) ) / 365.25 )\" title=\"Patient Age\" primary=\"false\" />   \n                        <column id=\"phonenumber\" name=\"IFNULL( d.phone, \'\')\" title=\"Patient Phone Number\" primary=\"false\" />\n                        <column id=\"rosterStatus\" name=\"IFNULL( d.roster_status, \'\') \" title=\"Roster Status\" primary=\"false\" />\n                        <column id=\"rosteredDate\" name=\"IF(d.roster_date IS NOT NULL, DATE_FORMAT( d.roster_date, \'%m-%d-%Y\'), \'\')\" title=\"Rostered Date (mm-dd-yyyy)\" primary=\"false\" />\n			<column id=\"lastVisit\" name=\"IF(app1.appointment_date IS NOT NULL, DATE_FORMAT( app1.appointment_date, \'%m-%d-%Y\'),\'\')\" title=\"Date of Last Visit (mm-dd-yyyy)\" primary=\"false\" />\n\n		</exportColumns>\n		<query>\n			<!-- Drilldown SQL Query here -->\n			\n			SELECT\n				d.*,\n				d.patient_status AS pt_status\n				FROM demographic d\n			\n				\n				-- Notations for last visit in appointments\n				LEFT JOIN (\n        				SELECT a.demographic_no, max(a.appointment_date) as appointment_date\n        				FROM appointment a, demographic d\n        				WHERE a.demographic_no = d.demographic_no\n        				AND d.provider_no = \'${provider}\'\n        				AND NOW() > DATE(a.appointment_date)\n        				AND a.status != \'D\' AND a.status != \'C\' AND a.status != \'N\'\n        				AND a.demographic_no > 0\n        				GROUP BY a.demographic_no\n				) app1 \n				ON (d.demographic_no = app1.demographic_no)\n\n				WHERE d.patient_status = \'AC\'\n				AND d.provider_no = \'${provider}\'\n                                AND DATEDIFF(CURDATE(), app1.appointment_date) &lt;= 365\n\n		</query>\n	</drillDownQuery>\n	<shared>false</shared>\n	<sharedMetricSetName>OntarioMD Patient Status</sharedMetricSetName>\n	<sharedMetricDataId>Status</sharedMetricDataId>\n	<sharedMappings>\n		<sharedMapping fromLabel=\"% Active, Seen within 12 months\" toLabel=\"Active, seen this year\"/>\n		<sharedMapping fromLabel=\"% Active, Seen 12-24 months ago\" toLabel=\"Active, seen within 1-2 yrs\"/>\n		<sharedMapping fromLabel=\"% Active, not seen in 24 months\" toLabel=\"Active, not seen in 2+ yrs\"/>\n		<sharedMapping fromLabel=\"% Inactive\" toLabel=\"Inactive\"/>\n		<sharedMapping fromLabel=\"% Deceased\" toLabel=\"Deceased\"/>\n		<sharedMapping fromLabel=\"% Other Patient Status\" toLabel=\"Other\"/>\n	</sharedMappings>	\n</indicatorTemplateXML>\n', b'1', b'0', 0, 'Active, seen this year', 'OntarioMD Patient Status');
INSERT INTO `indicatorTemplate` (`id`, `dashboardId`, `name`, `category`, `subCategory`, `framework`, `frameworkVersion`, `definition`, `notes`, `template`, `active`, `locked`, `shared`, `metricLabel`, `metricSetName`) VALUES
(1145, 6, 'Active Seen Within 1-2yr', 'OntarioMD Prac. Management', 'OMD-Patient Status', 'OSCAR EMR', '2018-02-14', '% of patients (Rostered and non-Rostered) in the practice based on their status, including last visit.', '', '<?xml version=\"1.0\" encoding=\"UTF-8\"?>\n<indicatorTemplateXML>\n	<author>Trinity Healthcare Technologies</author>\n	<uid></uid>\n	<heading>\n		<category>Practice Management</category>\n		<subCategory>OSCAR Patient Status</subCategory>\n		<name>Active Seen Within 1-2yr</name>\n		<metricSetName>OntarioMD Patient Status</metricSetName>\n                <metricLabel>Active, seen within 1-2 yrs</metricLabel>\n		<definition>% of patients (Rostered and non-Rostered) in the practice based on their status, including last visit.</definition>\n		<framework>OSCAR EMR</framework>\n		<frameworkVersion>02-14-2018</frameworkVersion>\n		<notes></notes>\n	</heading>\n	<indicatorQuery>\n		<version>02-14-2018</version>\n		<params>\n			<!-- \n				Use this parameter in the query as ${provider}\n				This parameter should be used for fetching patient\'s assigned to a MRP.\n				ie: WHERE demographic.provider_no = ${provider}\n			-->\n			<parameter id=\"provider\" name=\"provider_no\" value=\"loggedInProvider\" />\n			<parameter id=\"pstatus\" name=\"Patient Status\" value=\"\'AC\'\" />\n		</params>\n		<query>\n			<!-- Indicator SQL Query here -->\n			SELECT\n\n				-- PERCENT OF TOTAL PATIENTS NOTED AS ACTIVE SEEN WITHIN 12 MONTHS (latest visit &lt;= 12 months)\n				IF( COUNT(fin.patient) > 0, \n					SUM( IF( fin.pt_status = \'AC\' and DATEDIFF(CURDATE(),fin.last_visit) &lt;= 365  , 1, 0) )\n				, 0 ) AS \"% Active, Seen within 12 months\",\n			\n				-- PERCENT OF TOTAL PATIENTS NOTED AS ACTIVE SEEN 12-24 MONTHS AGO (latest visit &gt; 12 months and &lt; 24 months)\n				IF( COUNT(fin.patient) > 0, \n					 SUM( IF( fin.pt_status = \'AC\' and DATEDIFF(CURDATE(),fin.last_visit) > 365 and DATEDIFF(CURDATE(),fin.last_visit) &lt;= 730  , 1, 0) )\n				, 0 ) AS \"% Active, Seen 12-24 months ago\",\n				\n				-- PERCENT OF TOTAL PATIENTS NOTED AS ACTIVE NOT SEEN WITHIN 24 MONTHS (latest visit &gt; 24 months)\n				IF( COUNT(fin.patient) > 0, \n					SUM( IF( fin.pt_status = \'AC\' and (DATEDIFF(CURDATE(),fin.last_visit) > 730 OR fin.last_visit IS NULL)  , 1, 0) )\n				, 0 ) AS \"% Active, not seen in 24 months\",\n				\n				-- PERCENT OF TOTAL PATIENTS NOTED AS INACTIVE\n				IF( COUNT(fin.patient) > 0, \n					 SUM( IF( fin.pt_status = \'IN\' , 1, 0) )\n				, 0 ) AS \"% Inactive\",\n				\n				-- PERCENT OF TOTAL PATIENTS NOTED AS DECEASED\n				IF( COUNT(fin.patient) > 0, \n					  SUM( IF( fin.pt_status = \'DE\' , 1, 0) )\n				, 0 ) AS \"% Deceased\",\n				\n				-- PERCENT OF TOTAL PATIENTS NOTED AS OTHER (not active, not inactive, not deceased, not deleted?)\n				IF( COUNT(fin.patient) > 0, \n					  SUM( IF( fin.pt_status NOT IN (\'AC\',\'DE\',\'IN\') , 1, 0) )\n				, 0 ) AS \"% Other Patient Status\"\n				\n\n			FROM (\n				SELECT\n					d.demographic_no AS patient,\n					d.patient_status AS pt_status,\n					app1.appointment_date as last_visit\n				FROM demographic d\n			\n				\n				-- Notations for last visit in appointments\n				LEFT JOIN ( \n					SELECT a.demographic_no, max(a.appointment_date) as appointment_date\n        				FROM appointment a, demographic d\n        				WHERE a.demographic_no = d.demographic_no\n        				AND d.provider_no = \'${provider}\'\n        				AND NOW() >= DATE(a.appointment_date)\n        				AND a.status != \'D\' AND a.status != \'C\' AND a.status != \'N\'\n        				AND a.demographic_no > 0\n        				GROUP BY a.demographic_no\n				) app1 \n				ON (d.demographic_no = app1.demographic_no)\n\n				WHERE d.provider_no = \'${provider}\'\n			) fin\n		</query>\n	</indicatorQuery>\n	<drillDownQuery>\n		<version>02-14-2018</version>\n		<params>\n			<parameter id=\"provider\" name=\"provider_no\" value=\"loggedInProvider\" />	\n		</params>\n		<displayColumns>\n			<column id=\"demographic\" name=\"d.demographic_no\" title=\"Patient Id\" primary=\"true\" />\n			<column id=\"name\" name=\"CONCAT( d.last_name, \', \', d.first_name )\" title=\"Patient Name\" primary=\"false\" />\n			<column id=\"dob\" name=\"DATE_FORMAT( CONCAT(d.year_of_birth,\'-\',d.month_of_birth,\'-\',d.date_of_birth), \'%m-%d-%Y\' )\" title=\"Patient DOB (mm-dd-yyyy)\" primary=\"false\" />\n			<column id=\"age\" name=\"FLOOR( ABS( DATEDIFF( DATE( CONCAT(d.year_of_birth,\'-\',d.month_of_birth,\'-\',d.date_of_birth) ), NOW() ) ) / 365.25 )\" title=\"Patient Age\" primary=\"false\" />	\n                        <column id=\"phonenumber\" name=\"IFNULL( d.phone, \'\')\" title=\"Patient Phone Number\" primary=\"false\" />\n			<column id=\"rosterStatus\" name=\"IFNULL( d.roster_status, \'\') \" title=\"Roster Status\" primary=\"false\" />\n			<column id=\"rosteredDate\" name=\"IF(d.roster_date IS NOT NULL, DATE_FORMAT( d.roster_date, \'%m-%d-%Y\'), \'\')\" title=\"Rostered Date (mm-dd-yyyy)\" primary=\"false\" />\n			<column id=\"lastVisit\" name=\"IF(app1.appointment_date IS NOT NULL, DATE_FORMAT( app1.appointment_date, \'%m-%d-%Y\'),\'\')\" title=\"Date of Last Visit (mm-dd-yyyy)\" primary=\"false\" />\n		</displayColumns>\n		<exportColumns>\n			<column id=\"demographic\" name=\"d.demographic_no\" title=\"Patient Id\" primary=\"true\" />\n			<column id=\"name\" name=\"CONCAT( d.last_name, \', \', d.first_name )\" title=\"Patient Name\" primary=\"false\" />\n			<column id=\"dob\" name=\"DATE_FORMAT( CONCAT(d.year_of_birth,\'-\',d.month_of_birth,\'-\',d.date_of_birth), \'%m-%d-%Y\' )\" title=\"Patient DOB (mm-dd-yyyy)\" primary=\"false\" />\n                        <column id=\"age\" name=\"FLOOR( ABS( DATEDIFF( DATE( CONCAT(d.year_of_birth,\'-\',d.month_of_birth,\'-\',d.date_of_birth) ), NOW() ) ) / 365.25 )\" title=\"Patient Age\" primary=\"false\" />   \n                        <column id=\"phonenumber\" name=\"IFNULL( d.phone, \'\')\" title=\"Patient Phone Number\" primary=\"false\" />\n                        <column id=\"rosterStatus\" name=\"IFNULL( d.roster_status, \'\') \" title=\"Roster Status\" primary=\"false\" />\n                        <column id=\"rosteredDate\" name=\"IF(d.roster_date IS NOT NULL, DATE_FORMAT( d.roster_date, \'%m-%d-%Y\'), \'\')\" title=\"Rostered Date (mm-dd-yyyy)\" primary=\"false\" />\n			<column id=\"lastVisit\" name=\"IF(app1.appointment_date IS NOT NULL, DATE_FORMAT( app1.appointment_date, \'%m-%d-%Y\'),\'\')\" title=\"Date of Last Visit (mm-dd-yyyy)\" primary=\"false\" />\n\n		</exportColumns>\n		<query>\n			<!-- Drilldown SQL Query here -->\n			\n			SELECT\n				d.*,\n				d.patient_status AS pt_status\n				FROM demographic d\n			\n				\n				-- Notations for last visit in appointments\n				LEFT JOIN (\n        				SELECT a.demographic_no, max(a.appointment_date) as appointment_date\n        				FROM appointment a, demographic d\n        				WHERE a.demographic_no = d.demographic_no\n        				AND d.provider_no = \'${provider}\'\n        				AND NOW() > DATE(a.appointment_date)\n        				AND a.status != \'D\' AND a.status != \'C\' AND a.status != \'N\'\n        				AND a.demographic_no > 0\n        				GROUP BY a.demographic_no\n				) app1 \n				ON (d.demographic_no = app1.demographic_no)\n\n				WHERE d.patient_status = \'AC\'\n				AND d.provider_no = \'${provider}\'\n                                AND DATEDIFF(CURDATE(), app1.appointment_date) > 365\n                                AND DATEDIFF(CURDATE(), app1.appointment_date) &lt;= 730\n\n\n		</query>\n	</drillDownQuery>\n	<shared>false</shared>\n	<sharedMetricSetName>OntarioMD Patient Status</sharedMetricSetName>\n	<sharedMetricDataId>Status</sharedMetricDataId>\n	<sharedMappings>\n		<sharedMapping fromLabel=\"% Active, Seen within 12 months\" toLabel=\"Active, seen this year\"/>\n		<sharedMapping fromLabel=\"% Active, Seen 12-24 months ago\" toLabel=\"Active, seen within 1-2 yrs\"/>\n		<sharedMapping fromLabel=\"% Active, not seen in 24 months\" toLabel=\"Active, not seen in 2+ yrs\"/>\n		<sharedMapping fromLabel=\"% Inactive\" toLabel=\"Inactive\"/>\n		<sharedMapping fromLabel=\"% Deceased\" toLabel=\"Deceased\"/>\n		<sharedMapping fromLabel=\"% Other Patient Status\" toLabel=\"Other\"/>\n	</sharedMappings>	\n</indicatorTemplateXML>\n', b'1', b'0', 0, 'Active, seen within 1-2 yrs', 'OntarioMD Patient Status'),
(1993, 6, 'Patient Activity (Seen/Billed)', 'Panel', 'Active Patient Population', 'DoBC CPQI PSP Panel', '2017-08-02', 'Number of active patients in the practice seen within last 3 years and number not seen in last 3 years.', 'modified for Ontario billing', '<?xml version=\"1.0\" encoding=\"UTF-8\"?>\n<indicatorTemplateXML>\n	<author>OSCAR BC</author>\n	<uid></uid>\n	<heading>\n		<category>Panel</category>\n		<subCategory>Active Patient Population</subCategory>\n		<name>Patient Activity (Seen/Billed)</name>\n		<definition>Number of active patients in the practice seen within last 3 years and number not seen in last 3 years.</definition>\n		<framework>DoBC CPQI PSP Panel</framework>\n		<frameworkVersion>08-02-2017</frameworkVersion>\n		<notes>modified for Ontario billing</notes>\n		<graphType>bar</graphType>\n	</heading>\n	<indicatorQuery>\n		<version>03-13-2018</version>\n		<params>\n			<!-- \n				Use this parameter in the query as \'${provider}\'\n				This parameter should be used for fetching patient\'s assigned to a MRP.\n				ie: WHERE demographic.provider_no = \'${provider}\'\n			-->\n			<parameter id=\"provider\" name=\"provider_no\" value=\"loggedInProvider\" />\n			<parameter id=\"pstatus\" name=\"Patient Status\" value=\"\'AC\'\" />\n		</params>\n		<query>\n		  <!-- Indicator SQL Query here -->\nSELECT\n	SUM(fin.THREE) AS \"Number Active, Seen/Billed within 3 years\",\n	SUM(fin.NOT_SEEN_THREE) AS \"Number Active, Not seen/billed within 3 years\"\nFROM (\n	SELECT\n	  IF( DATE_SUB(CURDATE() , INTERVAL 3 YEAR) &lt;= DATE( MAX(cmn.observation_date) ) OR\n	    DATE_SUB(CURDATE() , INTERVAL 3 YEAR) &lt;= DATE( MAX(ch1.billing_date) ) ,1 ,0 ) AS THREE,\n	  IF( DATE_SUB(CURDATE() , INTERVAL 3 YEAR) &lt;= DATE( MAX(cmn.observation_date) ) OR\n	    DATE_SUB(CURDATE() , INTERVAL 3 YEAR) &lt;= DATE( MAX(ch1.billing_date) ) ,0 ,1 ) AS NOT_SEEN_THREE\n	FROM demographic d\n	LEFT JOIN casemgmt_note cmn\n	ON ( d.demographic_no = cmn.demographic_no AND cmn.signed = 1 AND cmn.provider_no != \'-1\'  )\n	LEFT JOIN billing_on_cheader1 ch1\n	ON ( d.demographic_no = ch1.demographic_no )\n	WHERE d.provider_no LIKE \'${provider}\'\n	AND d.patient_status LIKE ${pstatus}\n	GROUP BY d.demographic_no HAVING count(d.demographic_no) > -1\n) fin;\n		</query>\n	</indicatorQuery>\n	<drillDownQuery>\n		<version>03-03-2021</version>\n		<params>\n			<parameter id=\"provider\" name=\"provider_no\" value=\"loggedInProvider\" />	\n			<parameter id=\"pstatus\" name=\"Patient Status\" value=\"\'AC\'\" />\n		</params>\n		\n		<range>\n			<lowerLimit id=\"billingdate\" label=\"From Date\" name=\"Date\" value=\"DATE_SUB( NOW(), INTERVAL 3 YEAR )\" />\n			<upperLimit id=\"billingdate\" label=\"Date Today\" name=\"Date\" value=\"NOW()\" />\n			<lowerLimit id=\"visitdate\" label=\"From Date\" name=\"Date\" value=\"DATE_SUB( NOW(), INTERVAL 3 YEAR )\" />\n			<upperLimit id=\"visitdate\" label=\"Date Today\" name=\"Date\" value=\"NOW()\" />\n		</range>\n		\n		<displayColumns>\n			<column id=\"demographic\" name=\"d.demographic_no\" title=\"Patient Id\" primary=\"true\" />\n			<column id=\"name\" name=\"CONCAT( d.last_name, \', \', d.first_name )\" title=\"Patient Name\" primary=\"false\" />\n			<column id=\"dob\" name=\"DATE_FORMAT( CONCAT(d.year_of_birth,\'-\',d.month_of_birth,\'-\',d.date_of_birth), \'%Y-%m-%d\' )\" title=\"Date of Birth (yy-mm-dd)\" primary=\"false\" />\n			<column id=\"age\" name=\"TIMESTAMPDIFF(YEAR, DATE( CONCAT(d.year_of_birth,\'-\',d.month_of_birth,\'-\',d.date_of_birth) ), CURDATE() )\" title=\"Age\" primary=\"false\" />	\n			<column id=\"lastEncounter\" name=\'IF(MAX(cmn.observation_date) IS NOT NULL,DATE_FORMAT(MAX(cmn.observation_date),\"%Y%m%d\"),\"\")\' title=\"Last Encounter (yymmdd)\" primary=\"false\" />\n			<column id=\"lastBilling\" name=\"IF(MAX(bm.billing_date) IS NOT NULL,MAX(bm.billing_date),\'\')\" title=\"Last Billing (yymmdd)\" primary=\"false\" />\n		</displayColumns>\n		<exportColumns>\n			<column id=\"demographic\" name=\"d.demographic_no\" title=\"Patient Id\" primary=\"true\" />\n			<column id=\"name\" name=\"CONCAT( d.last_name, \', \', d.first_name )\" title=\"Patient Name\" primary=\"false\" />\n			<column id=\"dob\" name=\"DATE_FORMAT( CONCAT(d.year_of_birth,\'-\',d.month_of_birth,\'-\',d.date_of_birth), \'%Y-%m-%d\' )\" title=\"Date of Birth (yy-mm-dd)\" primary=\"false\" />\n			<column id=\"age\" name=\"TIMESTAMPDIFF(YEAR, DATE( CONCAT(d.year_of_birth,\'-\',d.month_of_birth,\'-\',d.date_of_birth) ), CURDATE() )\" title=\"Age\" primary=\"false\" />	\n			<column id=\"lastEncounter\" name=\'IF(MAX(cmn.observation_date) IS NOT NULL,DATE_FORMAT(MAX(cmn.observation_date),\"%Y%m%d\"),\"\")\' title=\"Last Encounter (yymmdd)\" primary=\"false\" />\n			<column id=\"lastBilling\" name=\"IF(MAX(bm.billing_date) IS NOT NULL,MAX(bm.billing_date),\'\')\" title=\"Last Billing (yymmdd)\" primary=\"false\" />\n		</exportColumns>\n		<drillDownActions>\n			<action id=\"tickler\" name=\"Tickler\"/>\n			<action id=\"patientStatusUpdate\" name=\"Set Patient Inactive\"/>\n		</drillDownActions>\n		<query>\n			<!-- Drilldown SQL Query here -->\nSELECT\n    d.*,\n    d.patient_status AS pt_status,\n    max(cmn.observation_date) as last_encounter,\n    max(bm.billing_date) as last_billing\nFROM demographic d\nLEFT JOIN casemgmt_note cmn\nON (  d.demographic_no = cmn.demographic_no AND cmn.signed = 1 AND cmn.provider_no != \'-1\'  )\nLEFT JOIN billing_on_cheader1 bm\nON ( d.demographic_no = bm.demographic_no )\nWHERE d.provider_no LIKE \'${provider}\'\nAND d.patient_status LIKE ${pstatus}\nGROUP BY d.demographic_no HAVING count(d.demographic_no) > -1\nORDER BY MAX(cmn.observation_date) ASC, MAX(bm.billing_date) ASC, d.demographic_no ASC\n		</query>\n	</drillDownQuery>	\n</indicatorTemplateXML>\n', b'1', b'0', 0, NULL, NULL),
(1994, 6, 'Patient Contact Information', 'Panel', 'Active Patient Population', 'DoBC CPQI PSP Panel', '2021-03-03', '# of active patients with incomplete contact information in comparison to # all active patients\n		', '\n		  # of active patients missing phone address or email\n		', '<?xml version=\"1.0\" encoding=\"UTF-8\"?>\r\n<indicatorTemplateXML>\r\n	<author>OSCAR BC</author>\r\n	<uid></uid>\r\n	<heading>\r\n		<category>Panel</category>\r\n		<subCategory>Active Patient Population</subCategory>\r\n		<name>Patient Contact Information</name>\r\n		<definition># of active patients with incomplete contact information in comparison to # all active patients\r\n		</definition>\r\n		<framework>DoBC CPQI PSP Panel</framework>\r\n		<frameworkVersion>03-03-2021</frameworkVersion>\r\n		<notes>\r\n		  # of active patients missing phone address or email\r\n		</notes>\r\n	</heading>\r\n	<indicatorQuery>\r\n		<version>03-13-2018</version>\r\n		<params>\r\n			<!-- \r\n				Use this parameter in the query as \'${provider}\'\r\n				This parameter should be used for fetching patient\'s assigned to a MRP.\r\n				ie: WHERE demographic.provider_no = \'${provider}\'\r\n			-->\r\n			<parameter id=\"provider\" name=\"provider_no\" value=\"loggedInProvider\" />\r\n			<parameter id=\"pstatus\" name=\"Patient Status\" value=\"\'AC\'\" />\r\n		</params>\r\n		<query>\r\n		  <!-- Indicator SQL Query here -->\r\nSELECT\r\n	SUM(fin.INCOMPLETE_CONTACT_INFO) AS \"Active, Incomplete Contact Information\",\r\n	SUM(fin.HAS_CONTACT_INFO) AS \"Active, With Contact Information\"\r\nFROM (\r\n	SELECT\r\n		IF( (LENGTH(phone) &lt; LENGTH(\"###-###-####\") OR LENGTH(e.value) &lt; LENGTH(\"###-###-####\")) OR (address is NULL OR address=\"\") OR (city is NULL OR city=\"\") OR (email is NULL OR email=\"\")  ,1 ,0 ) AS INCOMPLETE_CONTACT_INFO,\r\n		IF( (LENGTH(phone) &lt; LENGTH(\"###-###-####\") OR LENGTH(e.value) &lt; LENGTH(\"###-###-####\")) OR (address is NULL OR address=\"\") OR (city is NULL OR city=\"\") OR (email is NULL OR email=\"\")  ,0 ,1 ) AS HAS_CONTACT_INFO\r\n	FROM demographic d\r\n	LEFT JOIN demographicExt e ON d.demographic_no=e.demographic_no AND\r\n	  e.key_val=\'demo_cell\' AND e.date_time=(SELECT MAX(de.date_time) FROM demographicExt de WHERE e.demographic_no=de.demographic_no)\r\n	WHERE d.provider_no LIKE \'${provider}\'\r\n	AND d.patient_status LIKE ${pstatus}\r\n) fin;\r\n		</query>\r\n	</indicatorQuery>\r\n	<drillDownQuery>\r\n		<version>03-13-2018</version>\r\n		<params>\r\n			<parameter id=\"provider\" name=\"provider_no\" value=\"loggedInProvider\" />	\r\n			<parameter id=\"pstatus\" name=\"Patient Status\" value=\"\'AC\'\" />\r\n		</params>\r\n		<displayColumns>\r\n			<column id=\"demographic\" name=\"d.demographic_no\" title=\"Patient Id\" primary=\"true\" />\r\n			<column id=\"name\" name=\"CONCAT( d.last_name, \', \', d.first_name )\" title=\"Patient Name\" primary=\"false\" />\r\n			<column id=\"dob\" name=\"DATE_FORMAT( CONCAT(d.year_of_birth,\'-\',d.month_of_birth,\'-\',d.date_of_birth), \'%m-%d-%Y\' )\" title=\"Date of Birth (mm-dd-yy)\" primary=\"false\" />\r\n			<column id=\"age\" name=\"TIMESTAMPDIFF(YEAR, DATE( CONCAT(d.year_of_birth,\'-\',d.month_of_birth,\'-\',d.date_of_birth) ), CURDATE() )\" title=\"Age\" primary=\"false\" />\r\n			<column id=\"phone\" name=\"IF(d.phone IS NULL OR d.phone=\'\', \'N/A\', d.phone )\" title=\"Phone(H)\" primary=\"false\" />\r\n			<column id=\"phone2\" name=\"IF(d.phone2 IS NULL OR d.phone2=\'\', \'N/A\', d.phone2)\" title=\"Phone(W)\" primary=\"false\" />\r\n			<column id=\"phone3\" name=\"IF(e.value IS NULL OR e.value=\'\', \'N/A\', e.value)\" title=\"Cell Phone\" primary=\"false\" />\r\n			<column id=\"address\" name=\"IF(d.address IS NULL OR d.address=\'\', \'N/A\', d.address )\" title=\"Address\" primary=\"false\" />\r\n			<column id=\"city\" name=\"IF(d.city IS NULL OR d.city=\'\', \'N/A\', d.city )\" title=\"City\" primary=\"false\" />\r\n			<column id=\"email\" name=\"IF(d.email IS NULL OR d.email=\'\', \'N/A\', d.email )\" title=\"email\" primary=\"false\" />\r\n		</displayColumns>\r\n		<exportColumns>\r\n		        <column id=\"demographic\" name=\"d.demographic_no\" title=\"Patient Id\" primary=\"true\" />\r\n		  	<column id=\"firstName\" name=\"d.first_name\" title=\"First Name\" primary=\"false\" />\r\n                        <column id=\"lastName\" name=\"d.last_name\" title=\"Last Name\" primary=\"false\" />\r\n			<column id=\"dob\" name=\"DATE_FORMAT( CONCAT(d.year_of_birth,\'-\',d.month_of_birth,\'-\',d.date_of_birth), \'%m-%d-%Y\' )\" title=\"Date of Birth (mm-dd-yy)\" primary=\"false\" />\r\n			<column id=\"age\" name=\"TIMESTAMPDIFF(YEAR, DATE( CONCAT(d.year_of_birth,\'-\',d.month_of_birth,\'-\',d.date_of_birth) ), CURDATE() )\" title=\"Age\" primary=\"false\" />\r\n			<column id=\"phone\" name=\"IF(d.phone IS NULL OR d.phone=\'\', \'N/A\', d.phone )\" title=\"Phone(H)\" primary=\"false\" />\r\n			<column id=\"phone2\" name=\"IF(d.phone2 IS NULL OR d.phone2=\'\', \'N/A\', d.phone2)\" title=\"Phone(W)\" primary=\"false\" />\r\n			<column id=\"phone3\" name=\"IF(e.value IS NULL OR e.value=\'\', \'N/A\', e.value)\" title=\"Cell Phone\" primary=\"false\" />\r\n			<column id=\"address\" name=\"IF(d.address IS NULL OR d.address=\'\', \'N/A\', d.address )\" title=\"Address\" primary=\"false\" />\r\n			<column id=\"city\" name=\"IF(d.city IS NULL OR d.city=\'\', \'N/A\', d.city )\" title=\"City\" primary=\"false\" />\r\n			<column id=\"email\" name=\"IF(d.email IS NULL OR d.email=\'\', \'N/A\', d.email )\" title=\"email\" primary=\"false\" />\r\n		</exportColumns>\r\n		<query>\r\n			<!-- Drilldown SQL Query here -->\r\nSELECT\r\nd.*\r\nFROM demographic d\r\nLEFT JOIN demographicExt e ON d.demographic_no=e.demographic_no AND e.key_val=\'demo_cell\'\r\n  AND e.date_time=(SELECT MAX(de.date_time) FROM demographicExt de WHERE e.demographic_no=de.demographic_no)	\r\nWHERE d.provider_no LIKE \'${provider}\'\r\nAND d.patient_status LIKE ${pstatus}\r\nAND ((LENGTH(phone) &lt; LENGTH(\"###-###-####\") AND LENGTH(phone2) &lt; LENGTH(\"###-###-####\" ) AND LENGTH(e.value) &lt; LENGTH(\"###-###-####\")) OR (address is NULL OR address=\"\") OR (city is NULL OR city=\"\") OR (email is NULL OR email=\"\"));\r\n		</query>\r\n	</drillDownQuery>\r\n</indicatorTemplateXML>\r\n', b'1', b'0', 0, NULL, NULL),
(1995, 6, 'Active Patients', 'Panel', 'Active Patient Population', 'DoBC CPQI PSP Panel', '2017-08-02', 'Number of active patients in the practice last seen < 3 years, 3-5 years, 5+ years and never seen.', 'Altered from OSCAR BC sql to force provide percent by PHC', '<?xml version=\"1.0\" encoding=\"UTF-8\"?>\r\n<indicatorTemplateXML>\r\n	<author>OSCAR BC</author>\r\n	<uid></uid>\r\n	<heading>\r\n		<category>Panel</category>\r\n		<subCategory>Active Patient Population</subCategory>\r\n		<name>Active Patients</name>\r\n		<definition>Number of active patients in the practice last seen &lt; 3 years, 3-5 years, 5+ years and never seen.</definition>\r\n		<framework>DoBC CPQI PSP Panel</framework>\r\n		<frameworkVersion>08-02-2017</frameworkVersion>\r\n		<notes>Altered from OSCAR BC sql to force provide percent by PHC</notes>\r\n	</heading>\r\n	<indicatorQuery>\r\n		<version>03-03-2021</version>\r\n		<params>\r\n			<!-- \r\n				Use this parameter in the query as \'${provider}\'\r\n				This parameter should be used for fetching patient\'s assigned to a MRP.\r\n				ie: WHERE demographic.provider_no = \'${provider}\'\r\n			-->\r\n			<parameter id=\"provider\" name=\"provider_no\" value=\"loggedInProvider\" />\r\n			<parameter id=\"pstatus\" name=\"Patient Status\" value=\"\'AC\'\" />\r\n		</params>\r\n		<query>\r\n		  <!-- Indicator SQL Query here -->\r\nSELECT\r\n	ROUND(SUM(fin.THREE)*100/SUM(fin.TOTAL),1) AS \"% Active, Seen within 3 years\",\r\n	ROUND(SUM(fin.FIVETHREE)*100/SUM(fin.TOTAL),1) AS \"% Active, Seen 3-5 years ago\",\r\n	ROUND(SUM(fin.FIVEPLUS)*100/SUM(fin.TOTAL),1) AS \"% Active, not seen in 5+ years\",\r\n	ROUND(SUM(fin.NONE)*100/SUM(fin.TOTAL),1) AS \"% Active, no documented encounter\"\r\nFROM (\r\n	SELECT\r\n		IF( DATE_SUB(CURDATE() , INTERVAL 3 YEAR) &lt;= DATE( MAX(cmn.observation_date) ) ,1 ,0 ) AS THREE, \r\n		IF(  DATE_SUB(CURDATE() , INTERVAL 5 YEAR) &lt;= DATE( MAX(cmn.observation_date) ) AND\r\n		DATE( MAX(cmn.observation_date) ) &lt; DATE_SUB(CURDATE(), INTERVAL 3 YEAR), 1,0 ) AS FIVETHREE,\r\n		IF( DATE( MAX( cmn.observation_date ) ) &lt; DATE_SUB(CURDATE() , INTERVAL 5 YEAR) ,1 ,0 ) AS FIVEPLUS,\r\n		IF( cmn.note_id IS NULL ,1, 0 ) AS NONE,\r\n		IF (d.demographic_no IS NOT NULL,1,0) AS TOTAL\r\n	FROM demographic d\r\n	LEFT JOIN casemgmt_note cmn\r\n	ON (  d.demographic_no = cmn.demographic_no AND cmn.signed = 1 AND cmn.provider_no != \'-1\'  )\r\n	WHERE d.provider_no LIKE \'101\'\r\n	AND d.patient_status LIKE \'AC\'\r\n	GROUP BY d.demographic_no HAVING count(d.demographic_no) &gt; -1\r\n) fin;\r\n		</query>\r\n	</indicatorQuery>\r\n	<drillDownQuery>\r\n		<version>03-13-2018</version>\r\n		<params>\r\n			<parameter id=\"provider\" name=\"provider_no\" value=\"loggedInProvider\" />	\r\n			<parameter id=\"pstatus\" name=\"Patient Status\" value=\"\'AC\'\" />\r\n		</params>\r\n		<displayColumns>\r\n			<column id=\"demographic\" name=\"d.demographic_no\" title=\"Patient Id\" primary=\"true\" />\r\n			<column id=\"name\" name=\"CONCAT( d.last_name, \', \', d.first_name )\" title=\"Patient Name\" primary=\"false\" />\r\n			<column id=\"dob\" name=\"DATE_FORMAT( CONCAT(d.year_of_birth,\'-\',d.month_of_birth,\'-\',d.date_of_birth), \'%m-%d-%Y\' )\" title=\"Date of Birth (mm-dd-yy)\" primary=\"false\" />\r\n			<column id=\"age\" name=\"TIMESTAMPDIFF(YEAR, DATE( CONCAT(d.year_of_birth,\'-\',d.month_of_birth,\'-\',d.date_of_birth) ), CURDATE() )\" title=\"Age\" primary=\"false\" />	\r\n			<column id=\"lastEncounter\" name=\"IF(MAX(cmn.observation_date) IS NOT NULL,MAX(cmn.observation_date),\'\')\" title=\"Last Encounter\" primary=\"false\" />\r\n			<column id=\"patientStatus\" name=\"d.patient_status\" title=\"Patient Status\" primary=\"false\" />\r\n		</displayColumns>\r\n		<exportColumns>\r\n			<column id=\"demographic\" name=\"d.demographic_no\" title=\"Patient Id\" primary=\"true\" />\r\n			<column id=\"name\" name=\"CONCAT( d.last_name, \', \', d.first_name )\" title=\"Patient Name\" primary=\"false\" />\r\n			<column id=\"dob\" name=\"DATE_FORMAT( CONCAT(d.year_of_birth,\'-\',d.month_of_birth,\'-\',d.date_of_birth), \'%m-%d-%Y\' )\" title=\"Date of Birth (mm-dd-yy)\" primary=\"false\" />\r\n			<column id=\"age\" name=\"TIMESTAMPDIFF(YEAR, DATE( CONCAT(d.year_of_birth,\'-\',d.month_of_birth,\'-\',d.date_of_birth) ), CURDATE() )\" title=\"Age\" primary=\"false\" />	\r\n			<column id=\"lastEncounter\" name=\"IF(MAX(cmn.observation_date) IS NOT NULL,MAX(cmn.observation_date),\'\')\" title=\"Last Encounter\" primary=\"false\" />\r\n			<column id=\"patientStatus\" name=\"d.patient_status\" title=\"Patient Status\" primary=\"false\" />\r\n		</exportColumns>\r\n		<drillDownActions>\r\n			<action id=\"tickler\" name=\"Tickler\"/>\r\n			<action id=\"patientStatusUpdate\" name=\"Set Patient Inactive\"/>\r\n		</drillDownActions>\r\n		<query>\r\n			<!-- Drilldown SQL Query here -->\r\nSELECT\r\n    d.*,\r\n    d.patient_status AS pt_status,\r\n    max(cmn.observation_date) as last_encounter\r\nFROM demographic d\r\nLEFT JOIN casemgmt_note cmn\r\nON (  d.demographic_no = cmn.demographic_no AND cmn.signed = 1 AND cmn.provider_no != \'-1\'  )\r\nWHERE d.provider_no LIKE \'${provider}\'\r\nAND d.patient_status LIKE ${pstatus}\r\nGROUP BY d.demographic_no HAVING count(d.demographic_no) > -1			\r\n		</query>\r\n	</drillDownQuery>	\r\n</indicatorTemplateXML>\r\n', b'1', b'0', 0, NULL, NULL);
